div.script:
let games = [];
const API = "https://api.github.com/repos/bubbls/ugs-singlefile/contents/UGS-Files";

function formatName(n){
  let name = n.replace(".html","");
  name = name.replace(/^CL_?/i,"");
  name = name.replace(/([A-Z])/g," $1").trim();
  return name.toUpperCase();
}

function render(list){
  const g = document.getElementById("grid");
  if(!list.length){
    g.innerHTML = "<div class='loading'>NO GAMES</div>";
    return;
  }

  g.innerHTML = list.map(f => {
    const name = formatName(f.name);
    return `
      <div class="card" onclick="launch('${f.download_url}','${name}')">
        <div class="name">${name}</div>
      </div>
    `;
  }).join("");
}

function filterGames(){
  const q = document.getElementById("search").value.toLowerCase();
  render(games.filter(g => g.name.toLowerCase().includes(q)));
}

function launch(url,name){
  document.body.innerHTML = "";
  document.body.style.background = "#000";
  document.title = name;

  const iframe = document.createElement("iframe");
  iframe.src = url;
  iframe.style = "position:fixed;top:0;left:0;width:100vw;height:100vh;border:none;";
  document.body.appendChild(iframe);
}

async function load(){
  try{
    const res = await fetch(API);
    const data = await res.json();
    games = data.filter(x => x.name.endsWith(".html"));
    document.getElementById("search").placeholder =
      "SEARCH " + games.length + " GAMES...";
    render(games);
  }catch(e){
    document.getElementById("grid").innerHTML =
      "<div class='loading'>FETCH FAILED</div>";
  }
}

function stars(){
  const s = document.getElementById("stars");
  for(let i=0;i<80;i++){
    const d = document.createElement("div");
    d.className="star";
    d.style.width=d.style.height=Math.random()*2+"px";
    d.style.left=Math.random()*100+"%";
    d.style.top=Math.random()*100+"%";
    d.style.animationDuration=(50+Math.random()*80)+"s";
    s.appendChild(d);
  }
}

(function init(){
  stars();
  const a = localStorage.getItem("phantom_accent")||"#ff8c00";
  document.documentElement.style.setProperty("--accent",a);
  load();
})();
